class Solution:
    def sortMatrix(self, grid):
        n = len(grid)
        result = [row[:] for row in grid]
        diag_keys = set(r - c for r in range(n) for c in range(n))
        for key in diag_keys:
            cells = [(r, c) for r in range(n) for c in range(n) if r - c == key]
            cells.sort()
            values = [grid[r][c] for (r, c) in cells]
            if key >= 0:
                values.sort(reverse=True)
            else:
                values.sort()
            for (r, c), v in zip(cells, values):
                result[r][c] = v
        return result

