class Solution:
    def sortMatrix(self, grid):
        n = len(grid)
        diagonals = {}
        for r in range(n):
            for c in range(n):
                diagonals.setdefault(r - c, []).append((r, c))
        for key, cells in diagonals.items():
            values = [grid[r][c] for (r, c) in cells]
            values.sort(reverse=(key >= 0))
            for (r, c), v in zip(cells, values):
                grid[r][c] = v
        return grid

