var sortMatrix = function(grid) {
    const n = grid.length;
    const diagonals = new Map();
    for (let r = 0; r < n; r++) {
        for (let c = 0; c < n; c++) {
            const key = r - c;
            if (!diagonals.has(key)) diagonals.set(key, []);
            diagonals.get(key).push([r, c]);
        }
    }
    for (const [key, cells] of diagonals) {
        const values = cells.map(([r, c]) => grid[r][c]);
        if (key >= 0) values.sort((a, b) => b - a);
        else values.sort((a, b) => a - b);
        cells.forEach(([r, c], i) => { grid[r][c] = values[i]; });
    }
    return grid;
};
